def validate_blob_path(blob_path: str) -> bool:
    """Validate blob path to prevent path traversal and other injection attacks."""
    if not blob_path:
        return False
    
    # Reject path traversal attempts
    if '..' in blob_path or blob_path.startswith('/') or blob_path.startswith('\\'):
        return False
    
    # Reject backslashes
    if '\\' in blob_path:
        return False
    
    # Reject null bytes
    if '\x00' in blob_path:
        return False
    
    # Only allow alphanumeric, hyphens, underscores, dots, and forward slashes
    if not re.match(r'^[a-zA-Z0-9\-_./]+$', blob_path):
        return False
    
    # Normalize and re-check for traversal after normalization
    normalized = os.path.normpath(blob_path).replace('\\', '/')
    if normalized.startswith('..') or normalized.startswith('/'):
        return False
    
    # Ensure no segment is '..'
    segments = blob_path.split('/')
    for segment in segments:
        if segment == '..' or segment == '.' or segment == '':
            return False
    
    # Limit path length
    if len(blob_path) > 1024:
        return False
    
    return True


def validate_container_name(container_name: str) -> bool:
    """Validate Azure Blob Storage container name per Azure naming rules."""
